import { useEffect, useState } from 'react'
import { Catalog, AllowedPnRuntime, BusinessRules } from '../types'
import { loadCatalog, loadAllowedPnsRuntime, loadBusinessRules } from '../services/dataLoader'

interface UseDataResult {
  catalog: Catalog | null
  whitelist: AllowedPnRuntime | null
  businessRules: BusinessRules | null
  loading: boolean
  error: string | null
  reload: () => Promise<void>
}

export function useData(): UseDataResult {
  const [catalog, setCatalog] = useState<Catalog | null>(null)
  const [whitelist, setWhitelist] = useState<AllowedPnRuntime | null>(null)
  const [businessRules, setBusinessRules] = useState<BusinessRules | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const hydrate = async () => {
    setLoading(true)
    setError(null)

    try {
      const [nextCatalog, nextWhitelist, nextRules] = await Promise.all([
        loadCatalog(),
        loadAllowedPnsRuntime(),
        loadBusinessRules(),
      ])

      setCatalog(nextCatalog)
      setWhitelist(nextWhitelist)
      setBusinessRules(nextRules)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown data loading error')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    void hydrate()
  }, [])

  return {
    catalog,
    whitelist,
    businessRules,
    loading,
    error,
    reload: hydrate,
  }
}
