import { useEffect, useMemo, useState } from 'react'
import rawConfigurations from '../data/configurations.json'
import { Configuration } from '../types'
import {
  loadPersistedConfigurations,
  saveConfiguration as persistConfiguration,
} from '../services/configurationService'

function createBlankConfiguration(): Configuration {
  const now = new Date().toISOString()
  const numericId = String(Date.now() % 100000000).padStart(8, '0')

  return {
    id: `PXI-${numericId}`,
    name: '',
    description: '',
    owner: 'current-user',
    role: 'owner',
    deliveryPreference: 'assembled',
    isComplete: false,
    createdAt: now,
    lastSaved: now,
    version: 1,
    chassis: null,
    controller: null,
    modules: [],
    systemAccessories: [],
    serviceDetails: {
      program: null,
      duration: '3-year',
      software: {
        labview: true,
        labviewVersion: 'LabVIEW 2025',
        labviewLanguage: 'All Languages',
        labviewRealTimeModule: false,
        labviewFpgaModule: false,
        testStand: false,
        testStandVersion: 'TestStand 2024 Q4',
        labWindowsCvi: false,
        labWindowsCviVersion: 'NI LabWindows/CVI 2020',
      },
      calibrationPlan: 'none',
      calibrateBeforeShipping: false,
    },
    services: [],
    calibration: 'standard',
    totalPrice: 0,
    optimization: {
      blockingIssues: [],
      warnings: [],
      opportunities: [],
    },
  }
}

export function useConfiguration() {
  const [configurations, setConfigurations] = useState<Configuration[]>([])
  const [currentConfigId, setCurrentConfigId] = useState<string | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const hydrate = async () => {
      const loaded = (await loadPersistedConfigurations(rawConfigurations as Configuration[])) || []
      setConfigurations(loaded)
      if (loaded.length > 0) {
        setCurrentConfigId(loaded[0].id)
      }
      setLoading(false)
    }

    void hydrate()
  }, [])

  const currentConfiguration = useMemo(
    () => configurations.find((cfg) => cfg.id === currentConfigId) || null,
    [configurations, currentConfigId],
  )

  const createConfiguration = () => {
    const next = createBlankConfiguration()
    setConfigurations((prev) => [next, ...prev])
    setCurrentConfigId(next.id)
    void persistConfiguration(next)
    return next
  }

  const updateCurrentConfiguration = (patch: Partial<Configuration>) => {
    if (!currentConfigId) return

    setConfigurations((prev) =>
      prev.map((cfg) => {
        if (cfg.id !== currentConfigId) return cfg

        const updated: Configuration = {
          ...cfg,
          ...patch,
          lastSaved: new Date().toISOString(),
          version: cfg.version + 1,
        }

        void persistConfiguration(updated)
        return updated
      }),
    )
  }

  const selectConfiguration = (configId: string) => {
    setCurrentConfigId(configId)
  }

  return {
    loading,
    configurations,
    currentConfigId,
    currentConfiguration,
    createConfiguration,
    updateCurrentConfiguration,
    selectConfiguration,
  }
}
