function normalize(value: string | undefined | null): string {
  return (value || '').trim().toUpperCase()
}

function flatten(groups: { partNumbers: PartNumber[] }[]): PartNumber[] {
  return groups.flatMap((g) => g.partNumbers || [])
}

function formatWhitelistGroupName(name: string): string {
  return name
    .replace(/([A-Z]+)([A-Z][a-z])/g, '$1 $2')
    .replace(/([a-z0-9])([A-Z])/g, '$1 $2')
    .trim()
}

function extractChassisSlotCount(description: string | undefined): number | null {
  if (!description) return null
  const match = description.match(/(\d+)\s*[- ]\s*Slot/i)
  if (!match) return null
  const count = Number.parseInt(match[1], 10)
  return Number.isFinite(count) && count > 0 ? count : null
}

function extractSystemBandwidth(description: string | undefined): string {
  if (!description) return '—'
  const match = description.match(/Up to\s+[0-9.]+\s*[GMK]B\/s/i)
  return match ? match[0] : '—'
}

function extractPeripheralSlots(description: string | undefined): string {
  if (!description) return '—'
  const match = description.match(/(\d+)\s+Peripheral(?:\s+Expansion)?\s+Slot/i)
  return match ? match[1] : '0'
}

function extractHostInterface(part: PartNumber): string {
  const explicitHost = (part as any).hostInterface || (part as any).host
  if (explicitHost) return String(explicitHost)

  const description = part.description || ''
  if (/thunderbolt/i.test(description)) return 'Thunderbolt'
  if (/ethernet/i.test(description)) return 'Ethernet'
  if (/mxi/i.test(description)) return 'MXI'
  if (/usb/i.test(description)) return 'USB'

  return '—'
}

function makeWhitelistedPlaceholderPart(
  partNumber: string,
  category: 'controller' | 'module',
  groupName: string,
): PartNumber {
  const groupLabel = formatWhitelistGroupName(groupName)

  return {
    partNumber,
    description: `Whitelisted ${groupLabel} dataset item.`,
    price: 0,
    lifecycle: 'Active',
    rohs: true,
    reach: 'Compliant',
    primarySite: 'Unknown',
    model: category === 'controller'
      ? 'Controller model unavailable'
      : `${groupLabel} module (model unavailable)`,
    category,
    family: groupLabel,
  }
}

function findByModel(catalog: Catalog, category: 'chassis' | 'controller', model: string): PartNumber | null {
  const groups = category === 'chassis' ? catalog.chassis : catalog.controllers
  return flatten(groups).find((p) => normalize(p.model) === normalize(model)) || null
}

function getHealth(config: Configuration | null, catalog: Catalog | null, whitelist: AllowedPnRuntime | null, rules: BusinessRules | null) {
  if (!config || !catalog) {
    return { validation: null as ValidationResult | null, total: 0, lineItems: [] as PricingLineItem[], warnings: [] as string[] }
  }
  const pricing = calculatePriceBreakdown(config, catalog)
  const validation = validateConfiguration(config, {
    catalog,
    whitelist,
    businessRules: rules,
    hasPrice: Number.isFinite(pricing.total),
  })
  return { validation, total: pricing.total, lineItems: pricing.lineItems, warnings: pricing.warnings }
}


function money(value: number): string {
  return `$${value.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
}

function formatPxiConfigurationId(id: string): string {
  const normalized = normalize(id)
  if (!normalized.startsWith('PXI-')) {
    return id
  }

  const digits = normalized.replace(/[^0-9]/g, '')
  const padded = (digits.slice(-8) || '0').padStart(8, '0')
  return `PXI-${padded}`
}

function getPlatformLabel(id: string): 'PXI' | 'cRIO' | 'cDAQ' {
  const normalized = normalize(id)
  if (normalized.startsWith('CRIO-')) return 'cRIO'
  if (normalized.startsWith('CDAQ-')) return 'cDAQ'
  return 'PXI'
}

