function collectConfigurationPartReferences(configs: Configuration[]): Map<string, Set<string>> {
  const references = new Map<string, Set<string>>()
  const add = (partNumber: string | undefined, configId: string) => {
    const pn = normalize(partNumber)
    if (!pn) return
    if (!references.has(pn)) references.set(pn, new Set())
    references.get(pn)?.add(configId)
  }

  configs.forEach((config) => {
    const idLabel = formatPxiConfigurationId(config.id)
    add(config.chassis?.id, idLabel)
    ;(config.chassis?.accessories || []).forEach((pn) => add(pn, idLabel))
    add(config.chassis?.powerCord, idLabel)
    add(config.chassis?.rackMountKit, idLabel)

    add(config.controller?.id, idLabel)
    ;(config.controller?.accessories || []).forEach((pn) => add(pn, idLabel))
    add(config.controller?.powerCord, idLabel)

    ;(config.modules || []).forEach((module) => {
      add(module.partNumber, idLabel)
      ;(module.accessories || []).forEach((pn) => add(pn, idLabel))
    })

    ;(config.systemAccessories || []).forEach((pn) => add(pn, idLabel))
  })

  return references
}

function collectBusinessRulePartReferences(rules: BusinessRules | null): Map<string, Set<string>> {
  const references = new Map<string, Set<string>>()
  if (!rules) return references

  const add = (partNumber: string | undefined, rulePath: string) => {
    const pn = normalize(partNumber)
    if (!pn) return
    if (!references.has(pn)) references.set(pn, new Set())
    references.get(pn)?.add(rulePath)
  }

  ;(rules.integratedUnits || []).forEach((item, index) => {
    add(item.chassis, `integratedUnits[${index}].chassis`)
    add(item.controller, `integratedUnits[${index}].controller`)
  })

  ;(rules.requiredAccessories || []).forEach((rule, index) => {
    add(rule.partNumber, `requiredAccessories[${index}].partNumber`)
    ;(rule.accessories || []).forEach((accessory, accIndex) => {
      add(accessory.partNumber, `requiredAccessories[${index}].accessories[${accIndex}].partNumber`)
    })
  })

  ;(rules.chassisAccessories || []).forEach((rule, index) => {
    ;(rule.partNumbers || []).forEach((pn, partIndex) => add(pn, `chassisAccessories[${index}].partNumbers[${partIndex}]`))
  })

  return references
}

function resolveDatasetCategory(part: PartNumber | null, whitelistGroups: string[]): 'chassis' | 'controller' | 'module' | 'other' {
  if (part?.category === 'chassis' || part?.category === 'controller' || part?.category === 'module') {
    return part.category
  }

  if (whitelistGroups.includes('ModularChassis') || whitelistGroups.includes('IntegratedControllerAndChassis')) {
    return 'chassis'
  }

  if (
    whitelistGroups.includes('EmbeddedController')
    || whitelistGroups.includes('RemoteController')
    || whitelistGroups.includes('RackMountedController')
  ) {
    return 'controller'
  }

  if (whitelistGroups.length > 0) return 'module'
  return 'other'
}

function resolveDatasetSubgroup(
  category: 'chassis' | 'controller' | 'module' | 'other',
  part: PartNumber | null,
  whitelistGroups: string[],
): string {
  if (category === 'chassis') {
    if (part?.integrated || whitelistGroups.includes('IntegratedControllerAndChassis')) {
      return 'Integrated Chassis'
    }
    return 'Modular Chassis'
  }

  if (category === 'controller') {
    const directGroup = whitelistGroups.find((group) => CONTROLLER_WHITELIST_GROUP_LABELS[group])
    if (directGroup) return CONTROLLER_WHITELIST_GROUP_LABELS[directGroup]

    const description = `${part?.model || ''} ${part?.description || ''}`.toLowerCase()
    if (description.includes('rack')) return CONTROLLER_WHITELIST_GROUP_LABELS.RackMountedController
    if (description.includes('remote') || description.includes('ethernet') || description.includes('thunderbolt') || description.includes('usb')) {
      return CONTROLLER_WHITELIST_GROUP_LABELS.RemoteController
    }
    return CONTROLLER_WHITELIST_GROUP_LABELS.EmbeddedController
  }

  if (category === 'module') {
    const nonControllerGroup = whitelistGroups.find((group) => !CONTROLLER_WHITELIST_GROUP_LABELS[group] && group !== 'ModularChassis' && group !== 'IntegratedControllerAndChassis')
    if (nonControllerGroup) {
      return MODULE_WHITELIST_GROUP_LABELS[nonControllerGroup] || formatWhitelistGroupName(nonControllerGroup)
    }
    if (part?.family) return part.family
    return 'Other Modules'
  }

  return 'Uncategorized'
}

