/**
 * Configuration Persistence Service
 *
 * Handles saving, loading, and managing PXI configurations with:
 * - API endpoint persistence (with localStorage fallback)
 * - Schema versioning and migrations
 * - Retry logic for failed saves
 * - Export/import functionality
 */

import rawConfigurations from '../data/configurations.json'
import type { Configuration } from '../types'
import {
  getConfigurationClient,
  resetConfigurationClient,
  setConfigurationClient,
  type ConfigurationClient,
  type PersistedConfigurationRecord,
} from './configurationClient'

const CURRENT_SCHEMA_VERSION = 1

export interface ConfigurationMetadata {
  id: string
  name: string
  owner: string
  createdAt: string
  lastSaved: string
  schemaVersion: number
  isComplete: boolean
}

export interface PersistedConfiguration extends PersistedConfigurationRecord {}

export interface SaveResult {
  success: boolean
  id: string
  error?: string
  retryCount?: number
}

export interface LoadResult {
  success: boolean
  config?: PersistedConfiguration
  error?: string
}

export interface ListResult {
  success: boolean
  configurations?: ConfigurationMetadata[]
  error?: string
}

const LEGACY_CONFIGURATION_STORAGE_KEY = 'pxi-configurations'

// Retry configuration
const RETRY_CONFIG = {
  maxAttempts: 3,
  baseDelayMs: 500,
  maxDelayMs: 3000,
}

/**
 * Migrate configuration from old schema version to current
 */
function migrateConfiguration(config: any, fromVersion: number): PersistedConfiguration {
  let migrated = { ...config } as PersistedConfiguration

  // v0 -> v1: Ensure all required metadata fields exist
  if (fromVersion < 1) {
    migrated.createdAt = migrated.createdAt || new Date().toISOString()
    migrated.lastSaved = migrated.lastSaved || new Date().toISOString()
    migrated.version = migrated.version || 1
    migrated.owner = migrated.owner || 'system'
    migrated.role = migrated.role || 'owner'
  }

  migrated.schemaVersion = CURRENT_SCHEMA_VERSION
  return migrated
}

/**
 * Exponential backoff delay calculation
 */
function getBackoffDelay(attempt: number): number {
  const delay = RETRY_CONFIG.baseDelayMs * Math.pow(2, attempt)
  return Math.min(delay, RETRY_CONFIG.maxDelayMs)
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms))
}

function toMetadata(config: PersistedConfiguration): ConfigurationMetadata {
  return {
    id: config.id,
    name: config.name,
    owner: config.owner,
    createdAt: config.createdAt,
    lastSaved: config.lastSaved,
    schemaVersion: config.schemaVersion,
    isComplete: config.isComplete,
  }
}

function loadLegacyStoredConfigurations(): PersistedConfiguration[] {
  try {
    const stored = localStorage.getItem(LEGACY_CONFIGURATION_STORAGE_KEY)
    if (!stored) {
      return []
    }

    const parsed = JSON.parse(stored)
    if (!Array.isArray(parsed)) {
      return []
    }

    return parsed.map((config) => migrateConfiguration(config, config?.schemaVersion || 0))
  } catch {
    return []
  }
}

export function configureConfigurationClient(client: ConfigurationClient): void {
  setConfigurationClient(client)
}

export function resetConfiguredConfigurationClient(): void {
  resetConfigurationClient()
}

/**
 * Save configuration with retry logic
 */
export async function saveConfiguration(config: Configuration): Promise<SaveResult> {
  const persisted: PersistedConfiguration = {
    ...config,
    lastSaved: new Date().toISOString(),
    schemaVersion: CURRENT_SCHEMA_VERSION,
  }

  let lastError: string | undefined
  let attempt = 0

  while (attempt < RETRY_CONFIG.maxAttempts) {
    try {
      persisted._metadata = {
        saveAttempts: attempt + 1,
        lastSaveError: undefined,
      }

      const result = await getConfigurationClient().save(persisted)

      return {
        success: true,
        id: result.id,
        retryCount: attempt,
      }
    } catch (error) {
      lastError = error instanceof Error ? error.message : 'Unknown error'
      attempt++

      if (attempt < RETRY_CONFIG.maxAttempts) {
        const delay = getBackoffDelay(attempt - 1)
        await sleep(delay)
      }
    }
  }

  persisted._metadata = {
    saveAttempts: attempt,
    lastSaveError: lastError,
  }
  return {
    success: false,
    id: config.id,
    error: lastError,
    retryCount: attempt,
  }
}

/**
 * Load configuration by ID with schema migration
 */
export async function loadConfiguration(id: string): Promise<LoadResult> {
  try {
    const config = await getConfigurationClient().load(id)
    const migratedConfig = migrateConfiguration(config, config.schemaVersion || 0)

    return {
      success: true,
      config: migratedConfig,
    }
  } catch (error) {
    const errorMsg = error instanceof Error ? error.message : 'Unknown error'
    return {
      success: false,
      error: errorMsg,
    }
  }
}

/**
 * List all configurations for the current user
 */
export async function listConfigurations(): Promise<ListResult> {
  try {
    const configurations = (await getConfigurationClient().list()).map((config) =>
      toMetadata(migrateConfiguration(config, config.schemaVersion || 0)),
    )

    return {
      success: true,
      configurations,
    }
  } catch (error) {
    const errorMsg = error instanceof Error ? error.message : 'Unknown error'
    return {
      success: false,
      error: errorMsg,
    }
  }
}

export async function loadPersistedConfigurations(
  fallbackConfigurations: Configuration[] = rawConfigurations as Configuration[],
): Promise<Configuration[]> {
  try {
    const remoteConfigurations = await getConfigurationClient().list()
    if (remoteConfigurations.length > 0) {
      return remoteConfigurations.map((config) =>
        migrateConfiguration(config, config.schemaVersion || 0),
      )
    }

    const legacyConfigurations = loadLegacyStoredConfigurations()
    if (legacyConfigurations.length > 0) {
      return legacyConfigurations
    }

    return Array.isArray(fallbackConfigurations)
      ? fallbackConfigurations.map((config) => migrateConfiguration(config, config.schemaVersion || 0))
      : []
  } catch {
    const legacyConfigurations = loadLegacyStoredConfigurations()
    if (legacyConfigurations.length > 0) {
      return legacyConfigurations
    }

    return Array.isArray(fallbackConfigurations)
      ? fallbackConfigurations.map((config) => migrateConfiguration(config, config.schemaVersion || 0))
      : []
  }
}

/**
 * Delete configuration by ID
 */
export async function deleteConfiguration(id: string): Promise<{ success: boolean; error?: string }> {
  try {
    await getConfigurationClient().delete(id)

    return { success: true }
  } catch (error) {
    const errorMsg = error instanceof Error ? error.message : 'Unknown error'
    return { success: false, error: errorMsg }
  }
}

/**
 * Export configuration as JSON string
 */
export function exportConfigurationAsJson(config: PersistedConfiguration): string {
  return JSON.stringify(config, null, 2)
}

/**
 * Export configuration for download
 */
export function downloadConfiguration(config: PersistedConfiguration): void {
  const json = exportConfigurationAsJson(config)
  const blob = new Blob([json], { type: 'application/json' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = `config-${config.id}-${new Date().toISOString().split('T')[0]}.json`
  document.body.appendChild(a)
  a.click()
  document.body.removeChild(a)
  URL.revokeObjectURL(url)
}

/**
 * Import configuration from JSON
 */
export function importConfigurationFromJson(json: string): LoadResult {
  try {
    const config = JSON.parse(json)
    const migratedConfig = migrateConfiguration(config, config.schemaVersion || 0)
    return {
      success: true,
      config: migratedConfig,
    }
  } catch (error) {
    const errorMsg = error instanceof Error ? error.message : 'Invalid JSON'
    return {
      success: false,
      error: errorMsg,
    }
  }
}
