/**
 * Data Loader Service
 *
 * Loads and manages catalog, whitelist, business rules, and configuration data.
 */

import rawCatalog from '../data/catalog.json'
import rawWhitelist from '../data/allowed-pns-runtime.json'
import rawBusinessRules from '../data/businessRules.json'
import { AllowedPnRuntime, BusinessRules, Catalog, CatalogGroup } from '../types'

let catalogCache: Catalog | null = null
let whitelistCache: AllowedPnRuntime | null = null
let businessRulesCache: BusinessRules | null = null

function normalizePn(value: string | undefined | null): string {
  return (value || '').trim().toUpperCase()
}

function getAllowedPnSet(whitelist: AllowedPnRuntime): Set<string> {
  const fromAllowedList = (whitelist.allowedPns || []).map(normalizePn)
  const fromGroups = Object.values(whitelist.allowedByGroup || {})
    .flatMap((group) => group || [])
    .map(normalizePn)

  return new Set([...fromAllowedList, ...fromGroups].filter(Boolean))
}

function filterCatalogByWhitelist(catalog: Catalog, whitelist: AllowedPnRuntime): Catalog {
  const allowed = getAllowedPnSet(whitelist)

  const filterGroups = (groups: CatalogGroup[]): CatalogGroup[] => {
    return groups
      .map((group) => ({
        ...group,
        partNumbers: group.partNumbers.filter((pn) => allowed.has(normalizePn(pn.partNumber))),
      }))
      .filter((group) => group.partNumbers.length > 0)
  }

  return {
    ...catalog,
    chassis: filterGroups(catalog.chassis || []),
    controllers: filterGroups(catalog.controllers || []),
    modules: filterGroups(catalog.modules || []),
  }
}

export async function loadAllowedPnsRuntime(): Promise<AllowedPnRuntime> {
  if (whitelistCache) return whitelistCache
  whitelistCache = rawWhitelist as AllowedPnRuntime
  return whitelistCache
}

export async function loadBusinessRules(): Promise<BusinessRules> {
  if (businessRulesCache) return businessRulesCache
  businessRulesCache = rawBusinessRules as BusinessRules
  return businessRulesCache
}

export async function loadCatalog(): Promise<Catalog> {
  if (catalogCache) return catalogCache

  const [whitelist] = await Promise.all([loadAllowedPnsRuntime()])
  const catalog = rawCatalog as Catalog
  catalogCache = filterCatalogByWhitelist(catalog, whitelist)
  return catalogCache
}

export function clearCache(): void {
  catalogCache = null
  whitelistCache = null
  businessRulesCache = null
}
